let rawText = $input.first().json.text;
rawText = rawText.replace(/^```(?:json)?\s*|\s*```$/g, '').trim();
const startIdx = rawText.indexOf('{');
const endIdx = rawText.lastIndexOf('}');
if (startIdx !== -1 && endIdx !== -1) {
  rawText = rawText.substring(startIdx, endIdx + 1);
}

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  parsed = { type: 'chat' };
}

const msg = $('Telegram Trigger').first().json.message;
const sender = msg.from.first_name + (msg.from.last_name ? ' ' + msg.from.last_name : '');
const chatId = msg.chat.id;
const messageId = msg.message_id;
const messageText = msg.text;

const now = new Date();
const istanbulISO = now.toLocaleString('sv-SE', { timeZone: 'Europe/Istanbul' });

return [{
  json: {
    ...parsed,
    sender,
    chatId,
    messageId,
    rawMessage: messageText,
    timestamp: istanbulISO
  }
}];

const fs = require('fs');
const d = $input.first().json;
const filePath = '/data/downloads/expenses.jsonl';

const installments = (d.installments && parseInt(d.installments) > 1) ? parseInt(d.installments) : 1;
const amountPerInstallment = Math.round((d.amount / installments) * 100) / 100;

// Adds N months to an Istanbul-formatted date string "YYYY-MM-DD HH:mm:ss" without TZ conversion issues
function addMonths(dateStr, months) {
  const [datePart, timePart] = dateStr.split(' ');
  const [y, m, day] = datePart.split('-').map(Number);
  let totalMonths = (m - 1) + months;
  const newYear = y + Math.floor(totalMonths / 12);
  const newMonth = totalMonths % 12; // 0-indexed
  const maxDay = new Date(newYear, newMonth + 1, 0).getDate();
  const newDay = Math.min(day, maxDay);
  return `${newYear}-${String(newMonth + 1).padStart(2, '0')}-${String(newDay).padStart(2, '0')} ${timePart}`;
}

for (let i = 0; i < installments; i++) {
  const ts = addMonths(d.timestamp, i);
  const desc = installments > 1 ? `${d.description} (${i + 1}/${installments}. taksit)` : d.description;
  const record = {
    type: d.type,
    ts,
    user: d.sender,
    amount: amountPerInstallment,
    currency: d.currency,
    category: d.category,
    description: desc,
    raw: d.rawMessage,
    confidence: d.confidence
  };
  if (installments > 1) {
    record.installment_total = d.amount;
    record.installment_index = i + 1;
    record.installment_count = installments;
  }
  fs.appendFileSync(filePath, JSON.stringify(record) + '\n');
}

const confirmMessage = installments > 1
  ? `💸 <b>${d.amount} ${d.currency}</b> gider <b>${installments} taksit</b> olarak kaydedildi\n📅 Aylık taksit: <b>${amountPerInstallment} ${d.currency}</b>\n📂 Kategori: <i>${d.category}</i>\n📝 ${d.description}\n👤 ${d.sender}`
  : `${d.type === 'expense' ? '💸' : '💰'} <b>${d.amount} ${d.currency}</b> ${d.type === 'expense' ? 'gider' : 'gelir'} olarak kaydedildi\n📂 Kategori: <i>${d.category}</i>\n📝 ${d.description}\n👤 ${d.sender}`;

return [{ json: { ...d, saved: true, installments, amountPerInstallment, confirmMessage } }];

// Sorguyu çalıştır: gelir + gider + net analizi
const fs = require('fs');
const filePath = '/data/downloads/expenses.jsonl';
const q = $input.first().json;

if (!fs.existsSync(filePath)) {
  return [{ json: { ...q, empty: true, reason: 'Henüz kayıt yok' } }];
}

const content = fs.readFileSync(filePath, 'utf-8');
const lines = content.trim().split('\n').filter(l => l.length > 0);
const all = lines.map(l => { try { return JSON.parse(l); } catch { return null; } }).filter(Boolean);

// Backward compat: type yoksa expense kabul et
all.forEach(r => { if (!r.type) r.type = 'expense'; });

const dateFrom = q.date_from;
const dateTo = q.date_to;

let filtered = all.filter(e => {
  if (!e.ts) return false;
  const d = e.ts.split(' ')[0];
  return d >= dateFrom && d <= dateTo;
});

if (q.category_filter) filtered = filtered.filter(e => e.category === q.category_filter);
if (q.user_filter) filtered = filtered.filter(e => e.user.toLowerCase().includes(q.user_filter.toLowerCase()));

const rates = { TL: 1, EUR: 47, USD: 41, GBP: 53 };
const toTL = (a, c) => a * (rates[c] || 1);

let totalExpenseTL = 0, totalIncomeTL = 0;
const expenseByCategory = {}, incomeByCategory = {};
const byUser = {};

for (const e of filtered) {
  const tl = toTL(e.amount, e.currency);
  if (e.type === 'expense') {
    totalExpenseTL += tl;
    if (!expenseByCategory[e.category]) expenseByCategory[e.category] = { totalTL: 0, count: 0 };
    expenseByCategory[e.category].totalTL += tl;
    expenseByCategory[e.category].count += 1;
  } else if (e.type === 'income') {
    totalIncomeTL += tl;
    if (!incomeByCategory[e.category]) incomeByCategory[e.category] = { totalTL: 0, count: 0 };
    incomeByCategory[e.category].totalTL += tl;
    incomeByCategory[e.category].count += 1;
  }
  if (!byUser[e.user]) byUser[e.user] = { expenseTL: 0, incomeTL: 0 };
  if (e.type === 'expense') byUser[e.user].expenseTL += tl;
  else if (e.type === 'income') byUser[e.user].incomeTL += tl;
}

// Round
for (const k of Object.keys(expenseByCategory)) expenseByCategory[k].totalTL = Math.round(expenseByCategory[k].totalTL);
for (const k of Object.keys(incomeByCategory)) incomeByCategory[k].totalTL = Math.round(incomeByCategory[k].totalTL);
for (const u of Object.keys(byUser)) {
  byUser[u].expenseTL = Math.round(byUser[u].expenseTL);
  byUser[u].incomeTL = Math.round(byUser[u].incomeTL);
  byUser[u].netTL = byUser[u].incomeTL - byUser[u].expenseTL;
}

const netTL = totalIncomeTL - totalExpenseTL;
const savingsRate = totalIncomeTL > 0 ? Math.round((netTL / totalIncomeTL) * 100) : null;

const topExpenses = filtered
  .filter(e => e.type === 'expense')
  .map(e => ({ ...e, tl: Math.round(toTL(e.amount, e.currency)) }))
  .sort((a, b) => b.tl - a.tl)
  .slice(0, 10);

const topIncomes = filtered
  .filter(e => e.type === 'income')
  .map(e => ({ ...e, tl: Math.round(toTL(e.amount, e.currency)) }))
  .sort((a, b) => b.tl - a.tl)
  .slice(0, 10);

const expenseCount = filtered.filter(e => e.type === 'expense').length;
const incomeCount = filtered.filter(e => e.type === 'income').length;

return [{
  json: {
    ...q,
    empty: filtered.length === 0,
    expenseCount,
    incomeCount,
    totalExpenseTL: Math.round(totalExpenseTL),
    totalIncomeTL: Math.round(totalIncomeTL),
    netTL: Math.round(netTL),
    savingsRate,
    expenseByCategory,
    incomeByCategory,
    byUser,
    topExpenses,
    topIncomes
  }
}];

const fs = require('fs');
const filePath = '/data/downloads/expenses.jsonl';
const q = $input.first().json;

if (!fs.existsSync(filePath)) {
  return [{ json: { ...q, message: '📭 Henüz hiç kayıt yok, silinecek bir şey bulunamadı.' } }];
}

const content = fs.readFileSync(filePath, 'utf-8');
const lines = content.split('\n').filter(l => l.length > 0);
const records = lines.map((l, i) => {
  try {
    const r = JSON.parse(l);
    r._idx = i;
    if (!r.type) r.type = 'expense';
    return r;
  } catch { return null; }
}).filter(Boolean);

const searchAmount = (q.amount !== null && q.amount !== undefined) ? parseFloat(q.amount) : null;

let candidates = records.filter(r => {
  if (q.transaction_filter && q.transaction_filter !== 'both' && r.type !== q.transaction_filter) return false;
  if (q.category_filter && r.category !== q.category_filter) return false;
  if (q.currency && r.currency !== q.currency) return false;
  if (q.date_from && r.ts && r.ts.split(' ')[0] < q.date_from) return false;
  if (q.date_to && r.ts && r.ts.split(' ')[0] > q.date_to) return false;
  if (searchAmount !== null) {
    if (r.amount !== searchAmount && r.installment_total !== searchAmount) return false;
  }
  if (q.description_filter) {
    const f = q.description_filter.toLowerCase();
    if (!r.description || !r.description.toLowerCase().includes(f)) return false;
  }
  return true;
});

if (q.delete_last && candidates.length > 0) {
  candidates.sort((a, b) => (b.ts || '').localeCompare(a.ts || ''));
  candidates = [candidates[0]];
}

// Group installment rows together
function groupKey(r) {
  if (r.installment_total) {
    const baseDesc = (r.description || '').split(' (')[0];
    return `inst:${r.user}:${r.installment_total}:${baseDesc}`;
  }
  return `single:${r._idx}`;
}

const groupsMap = {};
for (const c of candidates) {
  const k = groupKey(c);
  if (!groupsMap[k]) groupsMap[k] = [];
  groupsMap[k].push(c);
}
// For installment groups, also pull in sibling rows that match the group (in case filter only caught one taksit row)
for (const k of Object.keys(groupsMap)) {
  if (!k.startsWith('inst:')) continue;
  const first = groupsMap[k][0];
  const baseDesc = (first.description || '').split(' (')[0];
  const siblings = records.filter(r => r.installment_total === first.installment_total && r.user === first.user && (r.description || '').split(' (')[0] === baseDesc);
  groupsMap[k] = siblings;
}
const groupList = Object.values(groupsMap);

let message;
if (groupList.length === 0) {
  message = '📭 Eşleşen kayıt bulunamadı. Filtreleri kontrol et (tutar/kategori/tarih).';
} else if (groupList.length === 1) {
  const group = groupList[0];
  const toRemove = new Set(group.map(r => r._idx));
  const remaining = records.filter(r => !toRemove.has(r._idx)).map(r => {
    const { _idx, ...rest } = r;
    return JSON.stringify(rest);
  });
  fs.writeFileSync(filePath, remaining.length ? remaining.join('\n') + '\n' : '');

  const first = group[0];
  const emoji = first.type === 'income' ? '💰' : '💸';
  const label = first.type === 'income' ? 'gelir' : 'gider';
  if (group.length > 1 && first.installment_total) {
    const baseDesc = (first.description || '').split(' (')[0];
    message = `🗑 ${emoji} <b>${first.installment_total} ${first.currency}</b> taksitli ${label} silindi (<b>${group.length} taksit</b>)\n📂 Kategori: <i>${first.category}</i>\n📝 ${baseDesc}\n👤 ${first.user}`;
  } else {
    const dateStr = (first.ts || '').split(' ')[0];
    message = `🗑 ${emoji} <b>${first.amount} ${first.currency}</b> ${label} silindi\n📂 Kategori: <i>${first.category}</i>\n📝 ${first.description}\n📅 ${dateStr}\n👤 ${first.user}`;
  }
} else {
  const previews = groupList.slice(0, 8).map((g, i) => {
    const r = g[0];
    const dateStr = (r.ts || '').split(' ')[0];
    const emoji = r.type === 'income' ? '💰' : '💸';
    const amt = r.installment_total || r.amount;
    const note = r.installment_total ? ` (${g.length} taksit)` : '';
    const desc = r.installment_total ? (r.description || '').split(' (')[0] : (r.description || '');
    return `${i + 1}) ${emoji} <b>${amt} ${r.currency}</b> — <i>${r.category}</i> — ${dateStr} — ${r.user}${note}\n   ${desc}`;
  }).join('\n');
  const extra = groupList.length > 8 ? `\n... ve <b>${groupList.length - 8}</b> kayıt daha` : '';
  message = `🤔 <b>${groupList.length} eşleşen kayıt</b> bulundu. Lütfen daha spesifik ol:\n\n${previews}${extra}\n\n💡 İpucu: kategori, tarih veya açıklama ekle (örn: "20 mayıs market 100 tl sil")`;
}

return [{ json: { ...q, message } }];
